import { useEffect, useState } from "react";
import MetricCard from "../components/MetricCard";
import PageHeader from "../components/PageHeader";
import { getAdminAlerts, getAdminDashboard } from "../services/api";

export default function AdminDashboardPage() {
  const [dashboard, setDashboard] = useState(null);
  const [alerts, setAlerts] = useState([]);

  useEffect(() => {
    const load = async () => {
      const [dashboardData, alertsData] = await Promise.all([getAdminDashboard(), getAdminAlerts()]);
      setDashboard(dashboardData);
      setAlerts(alertsData.slice(0, 3));
    };
    load();
  }, []);

  return (
    <>
      <PageHeader title="Admin Overview" description="A summary landing page for operational health, alerts, and quick admin awareness." />
      <div className="card-grid">
        <MetricCard label="Total Users" value={dashboard?.total_users || 0} />
        <MetricCard label="Appointments Today" value={dashboard?.appointments_today || 0} />
        <MetricCard label="Active Medications" value={dashboard?.active_medications || 0} />
        <MetricCard label="Open Alerts" value={dashboard?.alerts_count || 0} />
      </div>
      <div className="split-layout">
        <div className="panel">
          <h3 className="section-title">Latest Emergency Alerts</h3>
          <div className="summary-list">
            {alerts.length ? alerts.map((alert) => <div className="summary-item" key={alert.id}><strong>{alert.user.name}</strong><div>{alert.message}</div><span className="pill pill-danger">Immediate Attention Required</span></div>) : <p className="muted">No emergency alerts right now.</p>}
          </div>
        </div>
        <div className="panel">
          <h3 className="section-title">Quick Shortcuts</h3>
          <div className="shortcut-grid">
            <a className="shortcut-card" href="/admin/users">User Management</a>
            <a className="shortcut-card" href="/admin/appointments">Appointments</a>
            <a className="shortcut-card" href="/admin/analytics">Analytics</a>
            <a className="shortcut-card" href="/admin/alerts">Alerts</a>
            <a className="shortcut-card" href="/admin/system-control">System Control</a>
            <a className="shortcut-card" href="/admin/assistant">AI Assistant</a>
          </div>
        </div>
      </div>
    </>
  );
}
